var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"數小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 관리국 이동 전략 본부","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color> - 管理局移動戦略本部","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Administration Mobile Strategic HQ","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>管理局機動戰略本部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"……이거 샤레이드 측에는 면목이 없군.","JPN":"……シャレード側に合わせる顔がないな。","ENG":"...I owe Charade an apology for this.","TWN":"…我真的沒臉面對查雷德。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"설마, 이 도시에 강림했던 6종 침식체가 곧바로 샤레이드로 향할 줄이야.","JPN":"まさか、この都市に降臨した第6種がそのままシャレードに向かうとは。","ENG":"I never imagined the Category 6 C.O. that descended on that city would head straight for Charade.","TWN":"沒想到降臨在這座城市的第6類侵蝕體，竟然會直接朝查雷德移動。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프론트 베이 시니어</color>\\n잭","JPN":"<color=#ffd34c>フロントベイのシニア</color>\\nジャック","ENG":"<color=#ffd34c>Front Bay Senior</color>\\nJack","TWN":"<color=#ffd34c>前灣資深Senior</color>\\n傑克"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"최선을 다했지만, 우리에게는 6종 침식체를 대항할 수단이 없었지.","JPN":"全力を尽くしたが、我々にはやつに対抗する術がなかった。","ENG":"We did everything we could, but we had no means to oppose a Category 6 C.O.","TWN":"雖然我們已經盡力了，但沒有可以對抗第6類侵蝕體的手段。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"결국, 프론트 베이는 전조 현상을 막지 못하고 도시가 뿌리에 뒤덮이고 말았어.","JPN":"結局フロントベイは前兆現象を防げず、都市は根に覆われてしまった。","ENG":"In the end, Front Bay failed to stop the omen phenomenon, and the city was swallowed by roots.","TWN":"最終前灣未能阻止前兆現象，整座城市被根覆蓋。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 상황에서 우리가 할 수 있는 최선은…….","JPN":"あの状況で我々にできる精一杯が……","ENG":"In that situation, the best we could do...","TWN":"在那種情況下，我們能做的最好選擇……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리가 사용하지 못한 선로전환기와 황금향의 유산을 다음 도시로 인계하는 것이었네.","JPN":"活用できなかった線路転換器と黄金郷の遺産を次の都市に引き渡すことだったんだ。","ENG":"...was to pass on the unused Track Switcher and the Golden Vale's Legacy to the next city.","TWN":"就是把尚未使用的線路轉換器及黃金鄉的遺產，移交到下一座城市。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서 도착 예정 시간보다 일찍 선로전환기가 도착한 거구나?","JPN":"それで予定時間より早く線路転換器が届いたのね？","ENG":"So that's why the Track Switcher arrived earlier than expected?","TWN":"所以線路轉換器才會比預定時間更早抵達啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"네. 코치의 부탁으로, 저희가 샤레이드까지 선로전환기를 운반한 거고요.","JPN":"はい。コーチに頼まれて、私たちがシャレードまで線路転換器を運んだんです。","ENG":"Yes. At Coach's request, we transported the Track Switcher to Charade.","TWN":"是的。應教練的請求，由我們負責將線路轉換器運送到查雷德。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>카나리아 스쿼드</color>\\n건틀렛 리그 챔피언, 펠리세트","JPN":"<color=#ffd34c>カナリア・スクワッド</color>\\nガントレットリーグチャンピオン、フェリセット","ENG":"<color=#ffd34c>Canary Squad</color>\\nGauntlet League Champion, Félicette","TWN":"<color=#ffd34c>金絲雀小隊</color>\\n聖鎧聯賽冠軍，費莉塞特"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신의 희생 덕분에 선로전환기에 사용할 이터니움은 확보되었습니다.","JPN":"あなたの犠牲のおかげで、線路転換器に使うエタニウムを確保できました。","ENG":"Thanks to your sacrifice, we have secured enough Eternium to operate the Track Switcher.","TWN":"多虧你的犧牲，已確保線路轉換器所需的永恆之金。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이 자리에서 감사를 표합니다, 오지만디아스.","JPN":"この場を借りて感謝いたします、オジマンディアス。","ENG":"Allow me to express my gratitude here, Ozymandias.","TWN":"在此致上謝意，奧茲曼迪亞斯。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"희생은 뭔 희생? 나 안 죽었거든?","JPN":"犠牲？　私まだ死んでないけど？","ENG":"What sacrifice? I'm not dead, you know?","TWN":"什麼犧牲啊？我又沒死？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그나저나 허신이라니…….","JPN":"それにしても、虚神って……","ENG":"So anyway, a Hollow God, huh...","TWN":"話說回來，虛神啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그 염병할 괴물한테 죽을 뻔한 게 엊그제 같은데, 또 싸워야 한다고……?","JPN":"あのふざけた化け物に殺されかけたのが昨日のことみたいなのに、またあれと戦わないといけないのか？","ENG":"Feels like just yesterday I almost died fighting that damn monster, and now we're doing it again?","TWN":"前幾天才差點被那怪物殺了，現在又要再來一次……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>카나리아 스쿼드</color>\\n건틀렛 리그 챔피언, 라이카","JPN":"<color=#ffd34c>カナリア・スクワッド</color>\\nガントレットリーグチャンピオン、ライカ","ENG":"<color=#ffd34c>Canary Squad</color>\\nGauntlet League Champion, Laika","TWN":"<color=#ffd34c>金絲雀小隊</color>\\n聖鎧聯賽冠軍，萊卡"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"세피라의 수호자의 위치가 확인됐어.","JPN":"セフィラの守護者の位置を確認した。","ENG":"We've confirmed the location of the Guardian of Sephira.","TWN":"已確認塞菲拉守護者的位置。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"지금까지의 이동 경로를 추측하면, 선로전환기의 배치 지점과 부딪치게 될 거야.","JPN":"今までの移動経路から推測すると、線路転換器の配置地点とぶつかることになる。","ENG":"Judging by its movement path so far, it's going to collide with the Track Switcher deployment site.","TWN":"根據目前的移動路線推測，將會正面直擊線路轉換器的設置地點。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"결국, 싸움은 피할 수 없게 되겠지.","JPN":"戦いは避けられないだろう。","ENG":"In the end, we won't be able to avoid a fight.","TWN":"最終無法避免這場戰鬥了。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"아니요. 피하면 안 돼요.","JPN":"いいえ、むしろ避けちゃ駄目です。","ENG":"No. We must not avoid it.","TWN":"不，我們不可以迴避。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"반드시 우리 측에서 먼저 섬멸해야 해요.","JPN":"こちらから打って出て、絶対に殲滅すべきです。","ENG":"We have to eliminate it first.","TWN":"我們必須先發制人將其殲滅。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"6종 침식체는 다른 6종 침식체를 끌어들여요.","JPN":"第6種侵食体は、他の第6種をおびき寄せます。","ENG":"Category 6 C.O.s attract other Category 6 C.O.s.","TWN":"第6類侵蝕體會吸引其他第6類侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"녀석들을 방치하면, 결국 이 세계가 침식파에 붕괴해 버릴 거예요.","JPN":"やつらを放置したら、やがてこの世界は侵食波によって崩壊してしまいます。","ENG":"If we leave them alone, this world will eventually collapse under the Corruption rays.","TWN":"若放任不管，這個世界終將在侵蝕波中崩壞。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"게다가 이유는 잘 모르겠지만…….","JPN":"それに、理由はわからないけど……","ENG":"And for some reason...","TWN":"雖然還不清楚原因……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"아까 봤던 허신은 저희가 싸웠던 허신보다도 훨씬 크기가 컸어요.","JPN":"先程見た虚神は、私たちが戦った虚神よりずっと大きいものでした。","ENG":"...the Hollow God we saw earlier was far larger than the one we fought before.","TWN":"剛才看到的虛神，體型比我們曾經交戰過的虛神要大得多。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크기가 훨씬 컸다고?","JPN":"ずっと大きいだって？","ENG":"It was bigger?","TWN":"大得多？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"아마도 이 세계의 가능성을 흡수했기 때문이겠죠.","JPN":"おそらくこの世界の可能性を吸収したためでしょう。","ENG":"Most likely because it absorbed this world's possibilities.","TWN":"恐怕是因為吸收了這個世界的可能性吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그리고 가능성을 흡수하면 흡수할수록, 그 힘은 더욱 강력해질 겁니다.","JPN":"そして可能性を吸収すればするほど、その力は強大になります。","ENG":"And the more possibilities it absorbs, the stronger it will become.","TWN":"而且吸收得越多，它的力量就會越強大。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나 참, 지금도 죽을 뻔했는데, 여기서 더 강해진다고……?","JPN":"ったく、今でもあんなに強いのに、もっと強くなるっていうの……？","ENG":"You've got to be kidding me. I almost died already, and it's still getting stronger?","TWN":"真是的。現在就已經差點沒命了，結果還會變得更強……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그대들은 6종 침식체와 싸워봤다고 했지?","JPN":"君たちは第6種侵食体と戦ったことがあると言ったな？","ENG":"You said you've fought a Category 6 C.O. before.","TWN":"你們曾經說過有和第6類侵蝕體交戰過對吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그때는 어떻게 대처했나?","JPN":"その時はどう対処したんだ？","ENG":"How did you deal with it back then?","TWN":"當時是如何應對的？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"제가 가진 장비로 허신을 무력화할 수는 있었지만…….","JPN":"私の装備で虚神を無力化することはできたんですが……","ENG":"I was able to neutralize the Hollow God with my gear, but...","TWN":"雖然我手上的裝備能使虛神無力……"},"stage":{"bg":"CA_YOOMINA_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"결과적으로 허신을 쓰러트리기 위해서는 미나 씨의 울브즈 베인이 필요했어요.","JPN":"確実に止めを刺すためには、結局ミナさんのウルブズベインが必要でした。","ENG":"Ultimately, we needed Mina's Wolvesbane to bring it down.","TWN":"但最終要擊倒虛神，還是需要米娜小姐狼之災禍。"},"stage":{"bg":"CA_YOOMINA_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 미나 씨는 지금 그라운드 원에 계시니까…….","JPN":"でもミナさんは今、グラウンド・ワンにいるし……","ENG":"But Mina is currently in Ground One, so...","TWN":"可是米娜小姐現在人在G1……"},"stage":{"bg":"CA_YOOMINA_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 그럼 뾰족한 대책이 없는 거야?","JPN":"なんだ、じゃあこれといった対策はないってことか？","ENG":"So what, there's nothing we can do?","TWN":"什麼啊，那不就是完全沒對策嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이대로 가다간 선로전환기고 나발이고 다 개죽음이라고?","JPN":"このままだと線路転換器どころか皆犬死になるぞ？","ENG":"Track Switcher or not, we're all dead?","TWN":"照這樣下去別說線路轉換器了，大家全都得送命吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이 작전을 수립한 건, 최고 관리자라고 하셨죠?","JPN":"この作戦を立てたのは最高管理者だと言いましたね？","ENG":"This operation was devised by the Supreme Administrator, correct?","TWN":"這個是由最高管理者制定的作戰吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저는 그분이 안배한 <color=#ffd34c>대책</color>이라는 게 무엇인지 알 것 같군요.","JPN":"私はあの人の立てた<color=#ffd34c>対策</color>というものが何なのか、わかる気がします。","ENG":"I believe I understand what kind of <color=#ffd34c>countermeasure</color> he arranged.","TWN":"我想，我大概知道那位安排的<color=#ffd34c>對策</color>是什麼了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"정말이야, 람다?","JPN":"ちょっと、本当なの？　ラムダ。","ENG":"Really, Lamda?","TWN":"真的嗎，蘭達？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 대책이라는 게 뭔데? 알려줘!","JPN":"その対策って何よ？　教えて！","ENG":"Then what is this countermeasure? Tell me!","TWN":"那個對策是什麼？快說啊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그저 전력으로 버티는 겁니다. <color=#ffd34c>해결책</color>이 나타날 때까지.","JPN":"ただ全力で耐えるのです。<color=#ffd34c>解決策</color>が現れるまで。","ENG":"We endure with everything we have until a <color=#ffd34c>solution</color> appears.","TWN":"只是全力撐下去，直到<color=#ffd34c>解決方案</color>出現為止罷了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐어……?","JPN":"はあ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠깐, 설마……?","JPN":"待って、まさか……？","ENG":"Wait, don't tell me...","TWN":"等等，該不會……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그렇군, 버틴다라…….","JPN":"そうか。耐える、か……","ENG":"I see. Endure...","TWN":"原來如此，撐下去啊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"최고 관리자는 신뢰할만한 사람이다.","JPN":"最高管理者は信頼に値する人物だ。","ENG":"The Supreme Administrator is someone worthy of trust.","TWN":"最高管理者是值得信賴的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그자가 무언가를 안배했다면, 그것에 틀림은 없겠지.","JPN":"あの人が何らかの布石を打ったのなら、きっと間違いないだろう。","ENG":"If he made preparations, then there must be meaning behind it.","TWN":"既然他有所安排，那就必然不會有錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그러니 그저 버티는 것만으로 무언가를 해결할 수 있다면, 얼마든지 버텨주마.","JPN":"ただ耐えるだけで何かを解決できるというのなら、いくらでも耐えてみせる。","ENG":"So if simply enduring can resolve this, then I will endure as long as it takes.","TWN":"如果只要撐下去就能解決一切，那我會撐到底。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"들어라! 이 도시를 지키기 위해, 뜻을 합친 모든 이들이여!","JPN":"この都市を守るために集結した者たちよ、聞け！","ENG":"Hear me! All who have joined forces to protect this city!","TWN":"聽好了！為了守護這座城市而齊聚於此的所有人！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"설령, 태어난 출신이 다르고 살아온 삶이 다를지라도……!","JPN":"たとえ出自や歩んできた人生は違えど……！","ENG":"Even if your origins differ, even if the lives you've lived are not the same...!","TWN":"即使我們的出身與人生各不相同……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"설령, 그 소속과 신념 서로 믿는 신앙이 다를지라도……!","JPN":"たとえ所属と信念、信仰は違えど……！","ENG":"Even if your affiliations, beliefs, and faiths are different...!","TWN":"即使所屬、信念、信仰的神都不一樣……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"지금 이 순간은, 사사로운 목적은 뒤로한 채 우리 모두 힘을 합하라!","JPN":"今この瞬間、各自の私事はいったん置き、皆の力を合わせよう！","ENG":"In this moment, cast aside personal motives and unite your strength!","TWN":"在這一刻，我們拋開一切私心，合力戰鬥吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"세계를 위해서, 그리고 이 도시를 위해서 싸우는 거다!","JPN":"世界のために、この都市のために戦うのだ！","ENG":"Fight for the world, and for this city!","TWN":"為了世界，也為了這座城市而戰！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그 선봉은…….","JPN":"その先陣は……","ENG":"The vanguard shall be...","TWN":"而那先鋒……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"우리 조디악 나이츠가 맡겠다……!","JPN":"我々ゾディアックナイツが切る……！","ENG":"Us, the Zodiac Knights...!","TWN":"就交給我們十二宮騎士團……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};